INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'arlington'), 'RM-12', 'rm-12', 'Residential Medium-Density 12', 'This district is intended to encourage a wide range of low to medium-density housing types, especially single-family attached, duplexes, and townhouse projects, though single-family detached is also allowed. Maximum residential density is limited to 12 units per gross acre.', NULL, NULL, NULL, NULL, 20, NULL, NULL, 'One parking space per bedroom for multi-family units.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
