INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'arlington'), 'RMF-22', 'rmf-22', 'Residential Multi-Family 22', 'This district is established to provide opportunities for high-density multi-family residential uses with a maximum density of 22 units per acre. The district also allows attached residential, live/work units, and residential units over ground-floor non-residential uses.', NULL, NULL, NULL, 65, 25, 10, 10, 'One parking space per bedroom for multi-family units.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
