INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'arlington'), 'GC', 'gc', 'General Commercial', 'This district is intended primarily to provide sites for a broad range of commercial uses including restaurants, offices, personal and commercial services. Sites should provide an attractive appearance with landscaping, well-designed parking, and controlled traffic movement. This district is primarily intended for development of freestanding and integrated commercial structures along arterial streets in older sections of the city that are experiencing redevelopment.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Specific guidelines on parking lots.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
